// // This module decrements the counter value on the rising edge of the clock and sets the counter to zero when the reset signal is active.
module binary_counter_4bit (clk, rst, count);
   input clk, rst;
   output reg [3:0] count;

   always @(posedge clk) begin
      if (rst)
         count <= 4'b0000;
      else
         count <= count + 1;
   end
endmodule
